import java.util.*;

class Employee {
    public int id;
    public int importance;
    public List<Integer> subordinates;
}

public int getTotalImportance(List<Employee> employees, int id) {
    Map<Integer, Employee> emap = new HashMap<>();
    for (Employee emp : employees) {
        emap.put(emp.id, emp);
    }
    return dfs(emap, id);
}

public int dfs(Map<Integer, Employee> emap, int id) {
    int ans = emap.get(id).importance;
    for (int subId : emap.get(id).subordinates) {
        ans += dfs(emap, subId);
    }
    return ans;
}
```

